def my_min(values):
    # Guard: return None if list is empty
    if not values:
        return None
    # Use built‑in min to find the smallest element
    return min(values)

# Test cases (you can add more)
print(my_min([5, 2, 9]))   # Expected: 2
print(my_min([]))          # Expected: None
